import{c as t,S as a,j as o,m as d}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1783065655000}'),n={name:"getting-started/index.md"};function r(s,e,i,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting Started”">​</a></h1><p>This guide walks through installing Knowlery, initializing a vault, and understanding what changes after setup.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h2><p>Knowlery targets Obsidian desktop and requires community plugins to be enabled.</p><p>You also need Claude Code or OpenCode if you want to run agent workflows against the vault. Node.js and npm are required for optional tool preparation and the external skill browser.</p><div class="tip custom-block"><p class="custom-block-title">Desktop behavior</p><p>Knowlery uses local command-line tools and Electron desktop APIs for agent-oriented features. The current plugin manifest marks it as desktop-only.</p></div><h2 id="install-from-community-plugins" tabindex="-1">Install from Community plugins <a class="header-anchor" href="#install-from-community-plugins" aria-label="Permalink to “Install from Community plugins”">​</a></h2><p>Install Knowlery from Obsidian&#39;s community plugin directory for normal use.</p><ol><li>Open <strong>Settings -&gt; Community plugins</strong> in Obsidian.</li><li>Select <strong>Browse</strong>.</li><li>Search for <strong>Knowlery</strong>.</li><li>Install and enable the plugin.</li></ol><h2 id="install-beta-builds-with-brat" tabindex="-1">Install beta builds with BRAT <a class="header-anchor" href="#install-beta-builds-with-brat" aria-label="Permalink to “Install beta builds with BRAT”">​</a></h2><p>BRAT is the Beta Reviewers Auto-update Tool for Obsidian. Use it only when you want to test preview builds before they are published to the community plugin directory.</p><ol><li>Install BRAT in Obsidian.</li><li>Open BRAT settings.</li><li>Add this beta plugin repository: <code>https://github.com/JayJiangCT/knowlery</code>.</li><li>Enable Knowlery from <strong>Settings -&gt; Community plugins</strong>.</li></ol><h2 id="manual-install" tabindex="-1">Manual Install <a class="header-anchor" href="#manual-install" aria-label="Permalink to “Manual Install”">​</a></h2><ol><li>Download <code>main.js</code>, <code>manifest.json</code>, and <code>styles.css</code> from the latest GitHub release.</li><li>Create <code>.obsidian/plugins/knowlery/</code> inside your vault if it does not already exist.</li><li>Place the three files in that folder.</li><li>Reload Obsidian.</li><li>Enable Knowlery from <strong>Settings -&gt; Community plugins</strong>.</li></ol><h2 id="first-run" tabindex="-1">First Run <a class="header-anchor" href="#first-run" aria-label="Permalink to “First Run”">​</a></h2><p>After enabling the plugin, open Knowlery from the ribbon icon or command palette.</p><p>If the vault is not initialized, Knowlery shows setup entry points in the dashboard and settings tab.</p><p>The setup wizard asks you to choose a platform:</p><table tabindex="0"><thead><tr><th>Platform</th><th>Generated config</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>.claude/CLAUDE.md</code> plus <code>.claude/rules/</code></td></tr><tr><td>OpenCode</td><td><code>opencode.json</code> plus <code>.agents/rules/</code></td></tr></tbody></table><p>If you are upgrading from an older release, v0.5.0 adds knowledge bundle sharing and installing: a Bundles section on the dashboard, the <strong>Share knowledge bundle</strong> and <strong>Install knowledge bundle</strong> commands, the <code>Library/</code> folder for installed bundles, and a bundle-aware <code>/ask</code> skill. v0.4.0 kept the dashboard focused on one action-first home and moved diagnostics, rules, schema shortcuts, and the Skills library into the Knowlery settings tab. Bundled skills still auto-sync on version changes, and <code>SCHEMA.md</code> is migrated in place when missing anchor sections are found. Custom and forked skills are preserved.</p><p>If Knowlery detects an older BYOAO vault, the setup wizard can switch into migration mode and preserve the existing BYOAO/OpenCode files while configuring Knowlery for Claude Code.</p><h2 id="what-setup-creates" tabindex="-1">What Setup Creates <a class="header-anchor" href="#what-setup-creates" aria-label="Permalink to “What Setup Creates”">​</a></h2><p>Knowlery creates the knowledge workspace and agent configuration in your vault:</p><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>KNOWLEDGE.md</code></td><td>Vault operating guide for humans and agents</td></tr><tr><td><code>SCHEMA.md</code></td><td>Knowledge taxonomy and page conventions</td></tr><tr><td><code>INDEX.base</code></td><td>Obsidian Bases index for compiled knowledge pages</td></tr><tr><td><code>entities/</code></td><td>Named things such as people, tools, organizations, and projects</td></tr><tr><td><code>concepts/</code></td><td>Ideas, frameworks, theories, and mental models</td></tr><tr><td><code>comparisons/</code></td><td>Side-by-side analyses</td></tr><tr><td><code>queries/</code></td><td>Saved questions and research threads</td></tr><tr><td><code>.knowlery/manifest.json</code></td><td>Knowlery setup metadata</td></tr><tr><td><code>.agents/skills/</code></td><td>Canonical installed skill files</td></tr><tr><td><code>.agents/rules/</code></td><td>OpenCode rules and shared agent rules</td></tr><tr><td><code>.claude/skills/</code></td><td>Mirrored built-in skill files for Claude Code</td></tr><tr><td><code>.claude/CLAUDE.md</code></td><td>Claude Code vault instructions</td></tr><tr><td><code>.claude/rules/</code></td><td>Claude Code rules</td></tr><tr><td><code>opencode.json</code></td><td>OpenCode configuration</td></tr><tr><td><code>skills-lock.json</code></td><td>Skill source, version, and disabled-state metadata</td></tr></tbody></table><p>Normal use can also create private activity receipts, weekly summary reports, daily review request/result files, and Freshness Review request/result/sidecar files under <code>.knowlery/</code>.</p><h2 id="optional-tool-preparation" tabindex="-1">Optional Tool Preparation <a class="header-anchor" href="#optional-tool-preparation" aria-label="Permalink to “Optional Tool Preparation”">​</a></h2><p>The setup wizard can detect Claude Code, OpenCode, Node.js, Claudian, and skills tooling.</p><p>Missing optional tools are shown as selectable install or preparation steps. Already-installed tools are shown as read-only status rows. These actions are opt-in and run on your computer with your user permissions.</p><h2 id="open-the-dashboard" tabindex="-1">Open the Dashboard <a class="header-anchor" href="#open-the-dashboard" aria-label="Permalink to “Open the Dashboard”">​</a></h2><p>After setup, open the Knowlery dashboard. It is a single scrolling review surface:</p><table tabindex="0"><thead><tr><th>Section</th><th>Use it for</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>Start from the current activity context and choose the next small move</td></tr><tr><td>Suggested moves</td><td>Use reusable review prompts such as Process new material or Challenge an idea</td></tr><tr><td>Knowledge health</td><td>Review pending Freshness Review suggestions when they exist</td></tr><tr><td>This note</td><td>Review the active Markdown note and prepare a focused prompt</td></tr><tr><td>Recent activity</td><td>Scan private activity receipts and open the full activity list</td></tr><tr><td>This week</td><td>Generate a weekly summary, open the last report, or send it for review</td></tr><tr><td>Bundles</td><td>Share a reviewed knowledge bundle or install one shared with you</td></tr></tbody></table><p>Open <strong>Settings -&gt; Knowlery</strong> for diagnostics, rules and schema shortcuts, the Skills library, platform switching, activity logging, and maintenance actions.</p><h2 id="recommended-first-session" tabindex="-1">Recommended First Session <a class="header-anchor" href="#recommended-first-session" aria-label="Permalink to “Recommended First Session”">​</a></h2><ol><li>Initialize a clean test vault first.</li><li>Read the generated <code>KNOWLEDGE.md</code> and <code>SCHEMA.md</code>.</li><li>Open the dashboard and read Today&#39;s move, Suggested moves, and This note.</li><li>Add one or two real notes to the vault.</li><li>Generate a weekly summary, then open <strong>Settings -&gt; Knowlery</strong> and run diagnostics.</li></ol>',34)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
